
.chat-area {
  flex: 1;
  overflow-y: auto;
  padding: 0 8px;
  display: flex;
  flex-direction: column;
  gap: 4px;
  scroll-behavior: smooth;

  &::-webkit-scrollbar {
    width: 3px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.1);
    border-radius: 2px;
  }
}

.chat-empty {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: #475569;
  gap: 8px;

  i {
    font-size: 32px;
  }

  p {
    font-size: 13px;
  }
}

.chat-bubble-row {
  display: flex;
  max-width: 100%;
}

.user-row {
  justify-content: flex-end;
}

.char-row {
  justify-content: flex-start;
}

.chat-bubble {
  max-width: 82%;
  padding: 8px 12px;
  border-radius: 16px;
  font-size: 12px;
  line-height: 1.5;
}

.user-bubble {
  background: linear-gradient(135deg, #3b82f6, #2563eb);
  color: #e2e8f0;
  border-bottom-right-radius: 4px;
}

.char-bubble {
  background: rgba(255, 255, 255, 0.08);
  color: #cbd5e1;
  border-bottom-left-radius: 4px;
}

.bubble-name {
  font-size: 10px;
  font-weight: 600;
  color: #60a5fa;
  margin-bottom: 3px;
}

.bubble-text {
  word-break: break-word;
}
