
.phone-container {
  display: flex;
  justify-content: center;
  align-items: center;
  width: 100%;
  padding: 8px 0;
}

.phone-frame {
  width: 100%;
  max-width: 390px;
  aspect-ratio: 9 / 19;
  background: #1a1a2e;
  border-radius: 36px;
  border: 4px solid #2a2a3e;
  box-shadow:
    0 0 0 2px #0f0f1a,
    0 0 0 6px #1a1a2e,
    0 12px 40px rgba(0, 0, 0, 0.5);
  position: relative;
  overflow: hidden;
}

.phone-notch {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 150px;
  height: 28px;
  background: #0f0f1a;
  border-radius: 0 0 20px 20px;
  z-index: 10;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
}

.notch-speaker {
  width: 50px;
  height: 5px;
  background: #1a1a2e;
  border-radius: 3px;
}

.notch-camera {
  width: 10px;
  height: 10px;
  background: #1a1a2e;
  border-radius: 50%;
  border: 1px solid #2a2a3e;
}

.phone-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #0f0f23 0%, #16213e 50%, #0f0f23 100%);
  padding-top: 28px;
}

.phone-bottom-bar {
  height: 20px;
  background: transparent;
  flex-shrink: 0;
}
